#include <bits/stdc++.h>
using namespace std;

int n, m;
bool f[105][105];

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int a, b;
        cin >> a >> b;
        f[a][b] = true;
    }
    for (int k = 1; k <= n; k++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (f[i][k] && f[k][j]) {
                    f[i][j] = true;
                }
            }
        }
    }
    int ans = 0;
    for (int i = 1; i <= n; i++) {
        int cnt = 0;
        for (int j = 1; j <= n; j++) {
            if (f[i][j] || f[j][i]) {
                cnt++;
            }
        }
        if (cnt == n - 1) ans++;
    }
    cout << ans;
    return 0;
}
